sqlCommand.descr:
insert into TransX (KeyID, Co, GL, CCcat, TP, BusCat, TTY, ProdCode, PTF, TransCode, Flex1, Flex2, Flex3, Flex4, Flex5, Flex6, Flex7, Flex8, FSitem, ExpNode, Txt, RefKey1, RefKey2, RefKey3, ReinLoc, RiskTerr, Flex9, Amt1, Amt2, Amt3, Amt4) 
		(select '[batchID]-save',Co, GL, CCcat, TP, BusCat, TTY, ProdCode, PTF, TransCode, Flex1, Flex2, Flex3, Flex4, Flex5, Flex6, Flex7, Flex8, FSitem, ExpNode, Txt, RefKey1, RefKey2, RefKey3, ReinLoc, RiskTerr, Flex9, round(sum(Amt1),2) as Amt1, round(sum(Amt2),2) as Amt2, round(sum(Amt3),2) as Amt3, round(sum(Amt4),2) as Amt4 
		from TransX where KeyID = '[batchID]'  group by KeyID, Co, GL, CCcat, TP, BusCat, TTY, ProdCode, PTF, TransCode, Flex1, Flex2, Flex3, Flex4, Flex5, Flex6, Flex7, Flex8, FSitem, ExpNode, Txt, RefKey1, RefKey2, RefKey3, ReinLoc, RiskTerr, Flex9)
